const ALLOWED_SORT_COLUMNS = [
  "name",
  "price",
  "rating",
  "createdAt",
  "stock",
] as const;
type SortColumn = (typeof ALLOWED_SORT_COLUMNS)[number];

const ALLOWED_SORT_ORDERS = ["ASC", "DESC"] as const;
type SortOrder = (typeof ALLOWED_SORT_ORDERS)[number];

function isAllowedSortColumn(value: string): value is SortColumn {
  return ALLOWED_SORT_COLUMNS.includes(value as SortColumn);
}

function isAllowedSortOrder(value: string): value is SortOrder {
  return ALLOWED_SORT_ORDERS.includes(value.toUpperCase() as SortOrder);
}

function parsePositiveInt(value: unknown, fallback: number): number {
  const parsed = parseInt(String(value), 10);
  return Number.isFinite(parsed) && parsed > 0 ? parsed : fallback;
}

function parseNonNegativeFloat(value: unknown): number | null {
  const parsed = parseFloat(String(value));
  return Number.isFinite(parsed) && parsed >= 0 ? parsed : null;
}

